```go
func solve(s string) []string {
    segments := []string{}
    seen := map[string]bool{}
    start := 0
    for start < len(s) {
        currentSegment := ""
        i := start
        for i < len(s) {
            currentSegment += string(s[i])
            if !seen[currentSegment] {
                seen[currentSegment] = true
                segments = append(segments, currentSegment)
                start = i + 1
                break
            } else {
                i++
            }
        }
    }
    return segments
}
```

