function solve(s: string): string[] {
    const segments: string[] = [];
    const seen = new Set<string>();
    let start = 0;
    while (start < s.length) {
        let currentSegment = '';
        while (start < s.length) {
            currentSegment += s[start];
            if (!seen.has(currentSegment)) {
                seen.add(currentSegment);
                segments.push(currentSegment);
                start++;
                break;
            } else {
                start++;
            }
        }
    }
    return segments;
}

